mapper.sql:
SELECT 0 AS CHK /*체크박스*/ , NISHD.CTKEY /*센터 코드*/ , NISHD.OWKEY /*화주 코드*/ , OBHD.OBHDDAY /*출고희망일자*/ , NISHD.OBNISNO /*출고결품 번호*/ , OBHD.OBORDKEY /*오더코드*/ , NISHD.OBHDKEY /*릴리즈 코드*/ , NISHD.STNBARCODE /*등록STN*/ , NISHD.INSERTURKEY /*입력자*/ , NISHD.INSERTDATE /*입력일시*/ , SUM(COALESCE(NISDT.EXPCTQTY, 0)) AS TOT_EXPCTQTY /*총예정수량*/ , SUM(COALESCE(NISDT.CNFRMQTY, 0)) AS TOT_CNFRMQTY /*총확정수량*/ , SUM(COALESCE(NISDT.NISQTY, 0)) AS TOT_NISQTY /*총결품수량*/ , SUM(CASE NONICYN WHEN 'Y' THEN NISDT.NISQTY ELSE 0 END) AS TOT_EXIST_ICQTY /*총상품없음수량*/ , (CASE WHEN SUM(CASE NISDT.WKPRGRYN WHEN 'Y' THEN 1 ELSE 0 END) > 0 THEN 'Y' ELSE 'N' END) AS PDA_CNFRMYN /*PDA확정여부*/ , ( CASE WHEN (COUNT(NISDT.OBNISDTNO) - SUM(CASE NISDT.NISPRCSSTATUSCD WHEN '99' THEN 1 ELSE 0 END)) = SUM(CASE NISDT.NISPRCSSTATUSCD WHEN '00' THEN 1 ELSE 0 END) THEN '00' WHEN (COUNT(NISDT.OBNISDTNO) - SUM(CASE NISDT.NISPRCSSTATUSCD WHEN '99' THEN 1 ELSE 0 END)) = SUM(CASE NISDT.NISPRCSSTATUSCD WHEN '10' THEN 1 ELSE 0 END) THEN '10' WHEN (COUNT(NISDT.OBNISDTNO) - SUM(CASE NISDT.NISPRCSSTATUSCD WHEN '99' THEN 1 ELSE 0 END)) = SUM(CASE NISDT.NISPRCSSTATUSCD WHEN '20' THEN 1 ELSE 0 END) THEN '20' WHEN (COUNT(NISDT.OBNISDTNO) - SUM(CASE NISDT.NISPRCSSTATUSCD WHEN '99' THEN 1 ELSE 0 END)) >= SUM(CASE WHEN NISDT.NISPRCSSTATUSCD IN ('10','20') THEN 1 ELSE 0 END) THEN '20' ELSE NULL END ) AS OB_NISPRCS_STATUSCD /*주문결품처리상태*/ , (CASE WHEN SUM((CASE NONICYN WHEN 'Y' THEN 1 ELSE 0 END)) > 0 THEN 'Y' ELSE 'N' END) AS EXIST_IC_YN /*상품없음처리여부*/ , COALESCE(NISHD.CNFRMYN, 'N') AS CNFRMYN /*포장지시여부*/ , NISHD.CNFRMURKEY AS PCKG_IST_URKEY /*포장지시처리자*/ , NISHD.CNFRMDATE AS PCKG_IST_DATE /*포장지시처리일시*/ , NISHD.REWKOBHDKEY /*재작업 릴리즈 코드*/ FROM TWORK_INFO_OB_NIS_HD NISHD /*출고 결품 헤더 정보*/
INNER JOIN ( SELECT DISTINCT NISHD.CTKEY , NISHD.OWKEY , NISHD.OBNISNO FROM TWORK_INFO_OB_NIS_HD NISHD /*출고 결품 헤더 정보*/ INNER JOIN TWORK_INFO_OB_NIS_DT NISDT /*출고 결품 상세 정보*/ ON NISHD.CTKEY = NISDT.CTKEY AND NISHD.OWKEY = NISDT.OWKEY AND NISHD.OBNISNO = NISDT.OBNISNO LEFT OUTER JOIN TWORK_INFO_OB_HD OBHD /*출고 공통 정보*/ ON NISHD.CTKEY = OBHD.CTKEY AND NISHD.OWKEY = OBHD.OWKEY AND (NISHD.OBHDKEY = OBHD.OBHDKEY OR NISHD.REWKOBHDKEY = OBHD.OBHDKEY) WHERE NISHD.CTKEY = #{CTKEY}
AND NISHD.OWKEY = COALESCE(#{OWKEY}, #{sowkey})
AND OBHD.OBHDDAY BETWEEN #{OBHDDAY_FROM} AND #{OBHDDAY_TO}
AND NISDT.ICKEY IN
#{ickey}
AND NISDT.NISQTY BETWEEN #{NISQTYFROM} AND #{NISQTYTO}
AND COALESCE(NISDT.PKIMPSYN, 'N') = #{PKIMPSYN}
AND NISDT.NISPRCSSTATUSCD IN
#{nisprcsstatuscd}
) FIL ON NISHD.CTKEY = FIL.CTKEY AND NISHD.OWKEY = FIL.OWKEY AND NISHD.OBNISNO = FIL.OBNISNO
INNER JOIN TWORK_INFO_OB_NIS_DT NISDT /*출고 결품 상세 정보*/ ON NISHD.CTKEY = NISDT.CTKEY AND NISHD.OWKEY = NISDT.OWKEY AND NISHD.OBNISNO = NISDT.OBNISNO LEFT OUTER JOIN TWORK_INFO_OB_HD OBHD /*출고 공통 정보*/ ON NISHD.CTKEY = OBHD.CTKEY AND NISHD.OWKEY = OBHD.OWKEY AND (NISHD.OBHDKEY = OBHD.OBHDKEY OR NISHD.REWKOBHDKEY = OBHD.OBHDKEY) WHERE NISHD.CTKEY = #{CTKEY}
AND NISHD.OWKEY = COALESCE(#{OWKEY}, #{sowkey})
AND OBHD.OBHDDAY BETWEEN #{OBHDDAY_FROM} AND #{OBHDDAY_TO} GROUP BY NISHD.CTKEY /*센터 코드*/ , NISHD.OWKEY /*화주 코드*/ , OBHD.OBHDDAY /*출고희망일자*/ , NISHD.OBNISNO /*출고결품 번호*/ , OBHD.OBORDKEY /*오더코드*/ , NISHD.OBHDKEY /*릴리즈 코드*/ , NISHD.STNBARCODE /*스테이션 바코드*/ , NISHD.INSERTURKEY /*입력자*/ , NISHD.INSERTDATE /*입력일시*/ , NISHD.CNFRMYN /*포장지시여부*/ , NISHD.CNFRMURKEY /*포장지시처리자*/ , NISHD.CNFRMDATE /*포장지시처리일시*/ , NISHD.REWKOBHDKEY /*재작업 릴리즈 코드*/

/* wms-outbound-obnishold-sql-oracle.xml - selectNisHoldSql - 결품보류현황 - 헤더 조회 SQL */
SELECT *
  FROM (

