mapper.sql:
/* wms-outbound-obnishold-sql-oracle.xml - selectNisHoldDetailSql - 결품보류상세현황 - 조회 SQL */ SELECT NIS.CTKEY /*센터 코드*/ , NIS.OWKEY /*화주 코드*/ , NIS.OBHDDAY /*출고희망일자*/ , NIS.OBNISNO /*출고결품 번호*/ , NIS.OBORDKEY /*오더코드*/ , NIS.OBHDKEY /*릴리즈 코드*/ , NIS.STNBARCODE /*등록STN*/ , NIS.INSERTURKEY /*입력자*/ , NIS.INSERTDATE /*입력일시*/ , NIS.PDA_CNFRMYN /*PDA확정여부*/ , NIS.OB_NISPRCS_STATUSCD /*주문결품처리상태*/ , COALESCE(NONICYN, 'N') AS EXIST_IC_YN /*상품없음처리여부*/ , NID.ICKEY /*상품 코드*/ , IC.ICNM /*상품명*/ , NID.EXPCTQTY /*예정 수량*/ , NID.CNFRMQTY /*확정 수량*/ , NID.NISQTY /*결품 수량*/ , (CASE NONICYN WHEN 'Y' THEN NID.NISQTY ELSE 0 END) AS EXIST_IC_QTY /*상품없음수량*/ , COALESCE(NID.PKIMPSYN, 'N') AS PKIMPSYN /*피킹 불가 여부*/ , NID.NISPRCSSTATUSCD /*결품 처리 상태 코드*/ , COALESCE(NIS.CNFRMYN, 'N') AS CNFRMYN /*포장지시여부*/ , NIS.PCKG_IST_URKEY /*포장지시처리자*/ , NIS.PCKG_IST_DATE /*포장지시처리일시*/ , NIS.REWKOBHDKEY /*재작업 릴리즈 코드*/ FROM (
) NIS INNER JOIN TWORK_INFO_OB_NIS_DT NID ON NIS.CTKEY = NID.CTKEY AND NIS.OWKEY = NID.OWKEY AND NIS.OBNISNO = NID.OBNISNO INNER JOIN TWORK_MST_IC IC /*상품 마스터*/ ON NID.CTKEY = IC.CTKEY AND NID.OWKEY = IC.OWKEY AND NID.ICKEY = IC.ICKEY
AND NID.ICKEY IN
#{ickey}
AND NID.NISQTY BETWEEN #{NISQTYFROM} AND #{NISQTYTO}
AND COALESCE(NID.PKIMPSYN, 'N') = #{PKIMPSYN}
AND NID.NISPRCSSTATUSCD IN
#{nisprcsstatuscd}

