mapper.update:
/* wms-outbound-obnishold-sql-oracle.xml - updateObNisHold - 결품보류내역 - 출고결품 헤더 확정처리 업데이트 */
UPDATE TWORK_INFO_OB_NIS_HD /*출고 결품 헤더 정보*/
   SET CNFRMDATE = #{sysdate} /*확정 일시*/
	 , CNFRMURKEY = #{surkey} /*확정자*/
	 , CNFRMYN = 'Y' /*확정 여부*/

	 , REWKOBHDKEY = #{rewkobhdkey}

	 , UPDATEDATE = #{sysdate} /*수정 일시*/
	 , UPDATEURKEY = #{surkey} /*수정자*/
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND OBNISNO = #{obnisno}

/* wms-outbound-obnishold-sql-oracle.xml - updateObNisHoldDt - 결품보류내역 - 출고결품 상세 확정처리 업데이트 */
UPDATE TWORK_INFO_OB_NIS_DT /*출고 결품 상세 정보*/
   SET CNFRMQTY = #{cnfrmqty} /*확정 수량*/
	 , NISPRCSSTATUSCD = #{nisprcsstatuscd} /*결품 처리 상태 코드*/
	 , UPDATEDATE = #{sysdate} /*수정 일시*/
	 , UPDATEURKEY = #{surkey} /*수정자*/
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND OBNISNO = #{obnisno}
   AND OBNISDTNO = #{obnisdtno}

/* wms-outbound-obnishold-sql-oracle.xml - updateObHdInfo - 결품보류내역 - 출고공통 헤더 업데이트 */
UPDATE TWORK_INFO_OB_HD /*출고 공통 정보*/
   SET OBSTATUSCD = #{obstatuscd} /*출고 상태 코드*/
	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND OBHDKEY = #{obhdkey}

/* wms-outbound-obnishold-sql-oracle.xml - updateObDtInfo - 결품보류내역 - 재작업지시 - 출고공통 상세 업데이트 */
UPDATE TWORK_INFO_OB_DT /*출고 상세 정보*/
   SET ALQTY = 0
	 , PKISTQTY = 0
	 , PKQTY = 0
	 , CLASSIFSQTY = 0
	 , PAKQTY = 0
	 , NISQTY = 0
	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND OBHDKEY = #{obhdkey}

mapper.select:
/* wms-outbound-obnishold-sql-oracle.xml - updateObDtInfo - 결품보류내역 - 확정처리 - 결품보류 상세의 확정수량 합계 조회 */
SELECT COALESCE(SUM(CNFRMQTY), 0) AS CNFRMQTY_SUM
  FROM TWORK_INFO_OB_NIS_DT
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND OBNISNO = #{obnisno}

mapper.update:
/* wms-outbound-obnishold-sql-oracle.xml - updateObHdWkTypeCd - 결품보류내역 - 재작업지시 시 신규릴리즈코드의 작업유형 변경 */
UPDATE TWORK_INFO_OB_HD /*출고 공통 정보*/
   SET WKTYPECD = NULL
	 , PREOBHDKEY = NULL
	 , PKOBHDKEY = NULL
     , WAHDKEY = NULL
     , PIHDKEY = NULL
     , OBWKDATE = NULL
	 , DASSTNBARCODE = NULL
	 , DASCELLBARCODE = NULL
	 , CLASSIFCNTRBARCODE = NULL
	 , CLASSIFWKURKEY = NULL
	 , CLASSIFWKDATE = NULL
	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND OBHDKEY = #{obhdkey}

/* wms-outbound-obnishold-sql-oracle.xml - callGetObDtSummary - 재작업지시 시 신규릴리즈코드의 작업유형 재조회 */
{
	  CALL SP_GET_OB_DT_SUMMARY(
			#{ctkey,mode=IN,jdbcType=VARCHAR}
			, #{owkey,mode=IN,jdbcType=VARCHAR}
			, #{obhdkey,mode=IN,jdbcType=VARCHAR}
			, #{vol,mode=OUT,jdbcType=NUMERIC}
			, #{weight,mode=OUT,jdbcType=NUMERIC}
			, #{ordseptypecd,mode=OUT,jdbcType=VARCHAR}
			, #{wktypecd,mode=OUT,jdbcType=VARCHAR}
			, #{classifspeccd,mode=OUT,jdbcType=VARCHAR}
	  )
}
